const item = $input.first();
let J = item.json ?? {};

// Compatibilidade com payloads diferentes (Supabase triggers/realtime/edge)
let record = J.record ?? J.new ?? J?.data?.record ?? J?.data?.new ?? J;
if (record && typeof record === 'object' && record.record) record = record.record;

const user_email = String(record.user_email ?? record.userEmail ?? J.user_email ?? J.userEmail ?? '').trim();
const entry_id = String(record.id ?? J.id ?? '').trim();
const location_id = String(record.location_id ?? record.locationId ?? '').trim();
const note = record.note ? String(record.note) : '';
const recorded_at = String(record.recorded_at ?? record.recordedAt ?? '').trim();

let recorded_at_sp = recorded_at;
try {
  if (recorded_at) {
    const d = new Date(recorded_at);
    if (!Number.isNaN(d.getTime())) {
      recorded_at_sp = new Intl.DateTimeFormat('pt-BR', {
        timeZone: 'America/Sao_Paulo',
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit'
      }).format(d);
    }
  }
} catch (e) {}

if (!user_email) {
  throw new Error('user_email não encontrado no payload (necessário para enviar o e-mail).');
}

return [{
  json: {
    user_email,
    entry_id,
    type: 'clock_in',
    type_label: 'Entrada',
    recorded_at,
    recorded_at_sp,
    note,
    location_id,
  }
}];

